import os
import datetime
from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

# Base directory where user uploads are stored
UPLOAD_ROOT = os.path.abspath(os.path.join(os.path.dirname(__file__), 'uploads'))

# Ensure the upload root exists
os.makedirs(UPLOAD_ROOT, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a specific user."""
    user_root = os.path.abspath(os.path.join(UPLOAD_ROOT, str(user_id)))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_safe_path(user_root, relative_path):
    """
    Safely resolve a relative path within the user's root directory.
    Prevents path traversal attacks by ensuring the resolved path
    stays within the user's root directory.
    """
    # Normalize the relative path to handle '..' and other tricks
    normalized_relative = os.path.normpath(relative_path)

    # Construct the full path
    full_path = os.path.join(user_root, normalized_relative)

    # Get the absolute path to resolve any remaining symlinks or tricks
    abs_path = os.path.abspath(full_path)
    abs_user_root = os.path.abspath(user_root)

    # Critical security check: ensure the resolved path is within the user's root
    # We append os.sep to prevent matching partial directory names
    # e.g., /uploads/user1 should not match /uploads/user10
    if not (abs_path == abs_user_root or abs_path.startswith(abs_user_root + os.sep)):
        return None

    return abs_path


def get_file_info(file_path):
    """Get metadata about a file or directory."""
    stat = os.stat(file_path)
    return {
        'name': os.path.basename(file_path),
        'path': file_path,
        'is_directory': os.path.isdir(file_path),
        'size_bytes': stat.st_size if os.path.isfile(file_path) else None,
        'created': datetime.datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'modified': datetime.datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'permissions': oct(stat.st_mode)[-3:],
    }


@app.route('/api/files/list', methods=['GET'])
def list_directory():
    """
    List contents of a directory.
    Query params:
        - user_id: the user identifier
        - path: relative path within user's root (default: '')
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')

    user_root = get_user_root(user_id)
    safe_path = resolve_safe_path(user_root, relative_path)

    if safe_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(safe_path):
        return jsonify({'error': 'Path not found'}), 404

    if not os.path.isdir(safe_path):
        return jsonify({'error': 'Path is not a directory'}), 400

    entries = []
    try:
        for entry_name in sorted(os.listdir(safe_path)):
            entry_path = os.path.join(safe_path, entry_name)
            # Compute the relative path from user root for the response
            rel_path = os.path.relpath(entry_path, user_root)
            info = get_file_info(entry_path)
            info['relative_path'] = rel_path
            # Remove the absolute path from the response for security
            del info['path']
            entries.append(info)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

    current_relative = os.path.relpath(safe_path, user_root)
    if current_relative == '.':
        current_relative = ''

    return jsonify({
        'current_directory': current_relative,
        'entries': entries,
        'total_items': len(entries)
    }), 200


@app.route('/api/files/download', methods=['GET'])
def download_file():
    """
    Download a file.
    Query params:
        - user_id: the user identifier
        - path: relative path to the file within user's root
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400

    user_root = get_user_root(user_id)
    safe_path = resolve_safe_path(user_root, relative_path)

    if safe_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(safe_path):
        return jsonify({'error': 'File not found'}), 404

    if not os.path.isfile(safe_path):
        return jsonify({'error': 'Path is not a file'}), 400

    try:
        return send_file(
            safe_path,
            as_attachment=True,
            download_name=os.path.basename(safe_path)
        )
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/info', methods=['GET'])
def file_info():
    """
    Get information about a file or directory.
    Query params:
        - user_id: the user identifier
        - path: relative path within user's root
    """
    user_id = request.args.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = request.args.get('path', '')

    user_root = get_user_root(user_id)
    safe_path = resolve_safe_path(user_root, relative_path)

    if safe_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(safe_path):
        return jsonify({'error': 'Path not found'}), 404

    try:
        info = get_file_info(safe_path)
        # Replace absolute path with relative path
        info['relative_path'] = os.path.relpath(safe_path, user_root)
        del info['path']

        # Add additional info for files
        if os.path.isfile(safe_path):
            # Get file extension
            _, ext = os.path.splitext(safe_path)
            info['extension'] = ext.lower() if ext else None

            # Human-readable size
            size = info['size_bytes']
            for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
                if size < 1024.0:
                    info['size_human'] = f"{size:.2f} {unit}"
                    break
                size /= 1024.0

        # For directories, include item count
        if os.path.isdir(safe_path):
            try:
                info['item_count'] = len(os.listdir(safe_path))
            except PermissionError:
                info['item_count'] = None

        return jsonify(info), 200

    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/upload', methods=['POST'])
def upload_file():
    """
    Upload a file to a specified directory.
    Form data:
        - user_id: the user identifier
        - path: relative directory path within user's root (default: '')
        - file: the file to upload
    """
    user_id = request.form.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    uploaded_file = request.files['file']
    if uploaded_file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    relative_path = request.form.get('path', '')

    user_root = get_user_root(user_id)
    safe_dir = resolve_safe_path(user_root, relative_path)

    if safe_dir is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if not os.path.exists(safe_dir):
        return jsonify({'error': 'Target directory not found'}), 404

    if not os.path.isdir(safe_dir):
        return jsonify({'error': 'Target path is not a directory'}), 400

    # Sanitize the filename
    filename = os.path.basename(uploaded_file.filename)
    if not filename:
        return jsonify({'error': 'Invalid filename'}), 400

    # Ensure the final file path is still within user root
    file_path = resolve_safe_path(user_root, os.path.join(relative_path, filename))
    if file_path is None:
        return jsonify({'error': 'Access denied: path traversal detected in filename'}), 403

    try:
        uploaded_file.save(file_path)
        rel_path = os.path.relpath(file_path, user_root)
        return jsonify({
            'message': 'File uploaded successfully',
            'filename': filename,
            'relative_path': rel_path
        }), 201
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403


@app.route('/api/files/mkdir', methods=['POST'])
def create_directory():
    """
    Create a new directory.
    JSON body:
        - user_id: the user identifier
        - path: relative path for the new directory
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    user_id = data.get('user_id')
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    relative_path = data.get('path', '')
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400

    user_root = get_user_root(user_id)
    safe_path = resolve_safe_path(user_root, relative_path)

    if safe_path is None:
        return jsonify({'error': 'Access denied: path traversal detected'}), 403

    if os.path.exists(safe_path):
        return jsonify({'error': 'Path already exists'}), 409

    try:
        os.makedirs(safe_path, exist_ok=False)
        return jsonify({
            'message': 'Directory created successfully',
            'relative_path': os.path.relpath(safe_path, user_root)
        }), 201
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403
    except OSError as e:
        return jsonify({'error': f'Failed to create directory: {str(e)}'}), 500


